command:
mkdir -p space && printf 'metrics:
  - {id: dup, dimension: performance, source: x, unit: x, reporting_window: 1d, privacy: local-only, opt_in: false}
  - {id: dup, dimension: activity, source: x, unit: x, reporting_window: 1d, privacy: local-only, opt_in: true}
' > space/metrics.yaml && bash "$CLAUDE_PLUGIN_ROOT/space/validate-metric-schema.sh" --metrics space/metrics.yaml 2>err.txt; rc=$?; [ "$rc" -ne 0 ] && grep -q 'duplicate_id=dup' err.txt && echo blocked 1>&2
